+    #[test]
+    fn io_error_roundtrip_all_known_kinds() {
+        use io::ErrorKind::*;
+        let all_known = [
+            NotFound,
+            PermissionDenied,
+            ConnectionRefused,
+            ConnectionReset,
+            ConnectionAborted,
+            NotConnected,
+            AddrInUse,
+            AddrNotAvailable,
+            BrokenPipe,
+            AlreadyExists,
+            WouldBlock,
+            InvalidInput,
